mapper.select:
SELECT

FROM payment_channel_bank
WHERE payment_id = #{paymentId}
  AND currency = #{currency}

mapper.delete:
DELETE FROM payment_channel_bank
WHERE payment_id = #{paymentId}
  AND currency = #{currency}
  AND (bank_code, support_type) IN

      (#{item.bankCode}, #{item.supportType})

mapper.update:
UPDATE payment_channel_bank pcb
SET status = vals.status,
    update_time = #{updateTime}
FROM (
    VALUES

        (#{item.bankCode}, #{item.supportType}, #{item.status})

) AS vals(bank_code, support_type, status)
WHERE pcb.payment_id = #{paymentId}
  AND pcb.currency = #{currency}
  AND pcb.bank_code = vals.bank_code
  AND pcb.support_type = vals.support_type
